// Script Continued Below
// 2.8.0 - 2022-07-09 - raj - STRY0119137 - Stretch- Template UI Clean Up- Delete Top Template Task Confirmation Modal (moved delete to new script)
// 

function onSubmit() {
    var formAction = g_form.getActionName();
    if (formAction == 'delete_template_task') {
		var task_id = g_form.getUniqueValue();
		if(x_153465_discovert == undefined || x_153465_discovert.DTech_Task_Actions==undefined){
			ScriptLoader.getScripts(['x_153465_discovert.DTech_Task_Actions.jsdbx'], function() {
				_requestParameters(task_id, formAction, confirmDeleteTemplateTask);
			});
		} else {
			_requestParameters(task_id, formAction, confirmDeleteTemplateTask);
		}
		// returning true opens UI Page but does not allow user interaction, then auto closes the UI Page
        return false;
    }	
}

function confirmDeleteTemplateTask(response) {
	var params = {};
	var sParams = response.responseXML.documentElement.getAttribute("answer");
	params = JSON.parse(sParams);
	var _spModal;
	if(typeof spModal != 'undefined'){
		_spModal = spModal;
	}
	if(x_153465_discovert.DTech_Task_Actions==undefined){
		ScriptLoader.getScripts(['x_153465_discovert.DTech_Task_Actions.jsdbx'], function() {
			x_153465_discovert.DTech_Task_Actions.confirmDeleteTemplateTask(_spModal, params);
		});
	} else {
		// already loaded, just call it
		x_153465_discovert.DTech_Task_Actions.confirmDeleteTemplateTask(_spModal, params);
	}	
}

//NOTE: this may move out into another file to handle all rest calls from UI Script
function _requestParameters(task_id, action_name, callback){
	var ajax  = new GlideAjax('ClientTaskTemplateHelpers');
	ajax.addParam('sysparm_name', 'getTaskUIActionParamaters');
	ajax.addParam('sysparm_task_id', task_id);
	ajax.addParam('sysparm_action_name', action_name);
	ajax.getXML(callback);
}

